 1	import type { FC } from 'react';
 2	import { NameCellRenderer } from 'src/modules/Providers/views/details/tabs/Hosts/components/NameCellRenderer';
 3	
 4	import type { ResourceField } from '@components/common/utils/types';
 5	import { Td } from '@patternfly/react-table';
 6	
 7	import IDCellRenderer from '../IDCellRenderer';
 8	import LinkSpeedCellRenderer from '../LinkSpeedCellRenderer';
 9	import MTUCellRenderer from '../MTUCellRenderer';
10	import NetworkCellRenderer from '../NetworkCellRenderer';
11	
12	import type { HostCellProps, InventoryHostNetworkTriple } from './types';
13	
14	type RenderTdProps = {
15	  resourceData: InventoryHostNetworkTriple;
16	  resourceFieldId: string | null;
17	  resourceFields: ResourceField[];
18	};
19	
20	const cellRenderers: Record<string, FC<HostCellProps>> = {
21	  id: IDCellRenderer,
22	  linkSpeed: LinkSpeedCellRenderer,
23	  mtu: MTUCellRenderer,
24	  name: NameCellRenderer,
25	  network: NetworkCellRenderer,
26	};
27	
28	/**
29	 * Function to render a table cell (Td).
30	 * If the cell is an inventory cell (NETWORK_COUNT, STORAGE_COUNT, VM_COUNT, or HOST_COUNT)
31	 * and there's no inventory data, it won't render the cell.
32	 */
33	export const RenderTd = ({ resourceData, resourceFieldId, resourceFields }: RenderTdProps) => {
34	  if (!resourceFieldId) return <Td></Td>;
35	
36	  const CellRenderer = cellRenderers?.[resourceFieldId] ?? null;
37	
38	  return (
39	    <Td key={resourceFieldId} dataLabel={resourceFieldId}>
40	      <CellRenderer data={resourceData} fieldId={resourceFieldId} fields={resourceFields} />
41	    </Td>
42	  );
43	};

